module adc_processor (
    input [15:0] error_adc,
    output reg [3:0] range
);
    always @(*) begin
        if (error_adc < 1024)
            range = 4'b0000; // 0
        else if (error_adc < 2048)
            range = 4'b0001; // 1
        else if (error_adc < 3072)
            range = 4'b0010; // 2
        else if (error_adc < 4096)
            range = 4'b0011; // 3
        else
            range = 4'b1111; // Error
    end
endmodule
